var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"좌익 쪽 놈들의 퇴로를 차단했습니다!","JPN":"左翼のやつらの退路を遮断しました！","ENG":"The left flank has been sealed off!","TWN":"已經封鎖了左翼那些傢伙的退路！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"우익도 마찬가지입니다! 한점으로 몰아넣었으니 신호만 주십시오!","JPN":"右翼も同様です！　一か所に追い込みました！　合図だけください！","ENG":"Same with the right! We've driven them all into one spot, just give the signal!","TWN":"右翼也是一樣的！已經逼到一個點上了，請給我訊號！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아직 움직이는 놈들이 있습니다! 진형 사이의 틈을 넓히면 안 돼요!","JPN":"まだ動いているやつらがいます！　陣形に隙を作らないでください！","ENG":"Some are still moving! Don't let any gaps form in the formation!","TWN":"還有敵人在行動！不能讓陣型之間的間隙擴大！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"어…?","JPN":"あっ……？","ENG":"Huh...?","TWN":"呃…？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"비, 비행형 몇 마리가 빠져나왔어!","JPN":"ひ、飛行型が何匹か抜け出たぞ！","ENG":"A-a few fliers got through!","TWN":"有幾隻飛行型的怪物逃出來了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"움직이지 마! 진형이 붕괴되면 사상자만 늘어나!!","JPN":"動くな！　陣形が崩れると死傷者が増える！！","ENG":"Hold your positions! Break the formation and we'll lose more lives!!","TWN":"不要動！陣型一旦潰散，傷亡只會增加！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"치잇…!!","JPN":"ちっ……！！","ENG":"Tch...!!","TWN":"嘖…！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"지금입니다, 무구를 개방하세요!","JPN":"今です、武具を開放しなさい！","ENG":"Now! Unleash your Armaments!","TWN":"就是現在，開放武具吧！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저건, 부단장의 스콜피오 랜스?","JPN":"あれは、副団長のスコルピオランス？","ENG":"That's... Deputy's Scorpio Lance?","TWN":"那是，副團長的天蠍長槍？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만, 저 형태는…!!","JPN":"でも、あの形は……！！","ENG":"But that form...!!","TWN":"但是，那種形態是…！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그래서, 내가 어? 혼자서 괴수 다섯 마리를 쓰러트렸다니까?","JPN":"それで、俺がさ？　1人で怪獣を5匹は倒したんだよ。","ENG":"I'm telling you, I took down five C.O.s by myself, okay?","TWN":"所以，我一個人打倒了五隻怪獸，你信嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"우리가 이렇게 술 먹고 있는 것도~? 다 내 덕분… 끄억!","JPN":"こうやって酒飲んでるのもな～？　全部俺のおかげ……げぷっ！","ENG":"So the fact that we're all drinking now? Totally thanks to me– *Burp*","TWN":"我們能這樣喝酒～？都是我的功勞…嗝！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"하하! 딜란 경 좀 봐! 아주 그냥 확실히 취했어!","JPN":"はは！　ディラン卿が完全に酔っぱらってる！","ENG":"Haha! Look at Sir Dylan! He's totally drunk!","TWN":"哈哈！看看迪蘭！他真是醉得徹底啊！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"고작 세 잔에 곯아떨어지다니. 1번대도 별거 없구만?","JPN":"3杯で酔いつぶれるなんて、第1番隊も大したことねえな？","ENG":"Three drinks and he's out cold? So much for Squad 1's pride!","TWN":"才三杯就醉倒了。第一小隊也沒什麼嘛？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"우쒸! 지금 말 다 했어?!","JPN":"おら！　今何って言った！！","ENG":"Hey! You wanna say that again?!","TWN":"可惡！你說完了嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무슨 일이길래 그리 오작동 난 전쟁 골렘 같은 표정을 짓고 계십니까?","JPN":"どうして誤作動してしまったウォーゴーレムのようなお顔をされているのですか？","ENG":"What's with that stiff face? You look like a broken war golem.","TWN":"發生什麼事了，怎麼擺出一副戰爭傀儡故障的表情？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"술이 입에 맞지 않으신다면, 경께서 혁혁한 공을 세우셨으니 제 비장의 포도주라도 대접하겠습니다.","JPN":"お酒が口に合わないのなら、卿には輝かしい戦功を立てていただきましたし、私のとっておきのブドウ酒を開けますよ。","ENG":"If the drinks aren't to your liking, you did perform admirably. I could offer you my best wine.","TWN":"如果酒不合你的口味，你立下了赫赫戰功，我會奉上我的珍藏葡萄酒以示敬意。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전 미성년자입니다.","JPN":"私は未成年です。","ENG":"I'm not old enough to drink.","TWN":"我是未成年人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 포도주스는 없는데 곤란하네요.","JPN":"あら。ブドウジュースはありませんし、困りましたね。","ENG":"Oh dear. There is no grape juice on hand.","TWN":"哎呀，沒有葡萄汁，這可麻煩了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"함께 잔을 나누고 싶었는데, 유감스럽게도 혼자 즐겨야겠군요.","JPN":"一緒に盃をかわしたかったのですが、一人で飲むしかありませんね。","ENG":"I was hoping to share a toast, but I suppose I'll have to drink alone.","TWN":"本想與你共飲一杯，遺憾的是只能獨自享受了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인. 한 가지 여쭤볼 수 있겠습니까?","JPN":"夫人。一つ聞いてもいいですか？","ENG":"Ma'am. May I ask you something?","TWN":"夫人，我能問你一個問題嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 말씀하시지요.","JPN":"ええ。ご遠慮なく。","ENG":"Of course. Go ahead.","TWN":"好的，請說。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"싸움 도중 침식체에게 죽은 사람들이 있었습니다.","JPN":"戦闘の途中、侵食体によって亡くなった方たちがいました。","ENG":"Some people died during the battle, killed by C.O.s.","TWN":"在戰鬥中，有人被侵蝕體殺死了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그런데 지금의 분위기는 연회나 다름없군요.","JPN":"なのに、今の雰囲気は宴会となんら変わりない。","ENG":"And yet now, it feels like a celebration.","TWN":"不過現在的氣氛就像宴會一樣呢。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"지친 싸움의 피로를 푸는 데에 이만한 것이 없으니까요.","JPN":"疲れた戦闘の疲労をほぐすのには、宴の席が一番ですからね。","ENG":"There's nothing better for lifting weary spirits after a long fight.","TWN":"沒有什麼比這更能消除戰鬥的疲憊了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무슨 문제라도 있으십니까?","JPN":"どうしましたか？","ENG":"Is something wrong?","TWN":"有什麼問題嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"외부인인 제가 이런 말할 처지가 아니라는 것은 알고 있습니다만.","JPN":"部外者である私が言える立場ではないと、わかっていますが。","ENG":"I know it's not my place as an outsider, but...","TWN":"我知道我作為外人不應該說這些話。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"연회보다는 죽은 이의 넋을 기리는 편이 좋지 않을까 싶어…….","JPN":"宴会よりは、死んだ者の魂を偲ぶ方がいいのではないかと……","ENG":"Wouldn't it be better to mourn the fallen?","TWN":"我覺得與其舉辦宴會，不如悼念逝者的靈魂……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"에스텔. 제국에서 술을 마시는 행위를 무어라 부르는지 아십니까?","JPN":"エステル。帝国ではお酒を飲む行為をどう呼ぶか、ご存じですか？","ENG":"Esther. Do you know what we call drinking in the Empire?","TWN":"艾斯特。你知道在帝國喝酒的行為叫什麼嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"음주 행위에 어떤 미사여구가 붙을지는 모르겠군요.","JPN":"飲酒行為にどんな美辞麗句が付くのか知りませんが。","ENG":"I have no idea what poetic term you might use for it.","TWN":"我不知道飲酒行為會被冠以什麼樣的美麗辭藻。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"개인적으로, 술은 여흥 행위 정도로 여기고 있습니다.","JPN":"個人的に、お酒は余興程度と思っておりますので。","ENG":"Personally, I just think of it as a way to pass time.","TWN":"個人而言，我認為酒只是娛樂活動的一種。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 말씀처럼 제국에서도 술은 단순 여흥 행위에 불과했습니다.","JPN":"ふふ。おっしゃるとおり、帝国でもお酒は単なる余興に過ぎませんでした。","ENG":"Haha. That's how it used to be here as well.","TWN":"呵呵。正如你所說，在帝國中酒只是單純的娛樂活動而已。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"하지만 마왕의 창궐 이후 일상의 평화로움이 사라지자.","JPN":"ですが魔王の降臨以来、日常の平和が消えると。","ENG":"But after the Demon Lord's rise and the end of peace...","TWN":"然而，自從魔王肆虐之後，日常的平靜消失了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어느 순간부터 제국의 술은 하나의 전통으로 자리잡기 시작했지요.","JPN":"ある瞬間から帝国のお酒は一つの伝統として定着し始めました。","ENG":"Drinking became something else. A tradition.","TWN":"從某個時刻起，帝國的酒開始成為一種傳統。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 전쟁 이후 술을 마시며 죽은 이들을 기리는 겁니다.","JPN":"ええ。戦争の後は、お酒を酌み交わしながら死者を偲ぶのです。","ENG":"Yes. After battle, we drink to honor the dead.","TWN":"是的。戰爭結束後，我們會喝酒紀念那些逝去的人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제국에서는 이를 <color=#ffd34c>슬픔을 삼킨다</color>고 말합니다.","JPN":"帝国ではこれを<color=#ffd34c>悲しみを飲む</color>と言います。","ENG":"In the Empire, we call it <color=#ffd34c>swallowing sorrow</color>.","TWN":"帝國稱之為<color=#ffd34c>吞噬傷痛</color>。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……술에 취해 억지로 감정을 억누른다는 겁니까?","JPN":"……酔いで無理やり感情を抑えるということですか？","ENG":"...So you're just numbing yourselves with alcohol?","TWN":"……是說借酒來勉強壓抑情感嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"억지로라는 말은 어폐가 있어 보이는군요.","JPN":"無理やりとは語弊がありますね。","ENG":"\\"Just\\" numbing isn't quite right.","TWN":"勉強這個詞似乎有些不妥。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"혹, 경께서는 숲에서 나눈 클링턴 씨에 관한 이야기를 기억하시는지요?","JPN":"卿は森でクリントンさんについて交わした会話を覚えていますか？","ENG":"Do you remember the story about Mr. Clinton from the forest?","TWN":"你還記得在森林裡談論克林頓先生的事嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어렴풋이 기억하고 있습니다.","JPN":"なんとなく覚えています。","ENG":"Vaguely.","TWN":"我依稀記得。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"분명, 그분께서는 역병에 걸리셨다 했죠.","JPN":"確か、あの方は疫病にかかっていると。","ENG":"He was said to have fallen ill, right?","TWN":"你說他得了瘟疫。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"클링턴 씨는 본래 점잖으신 분이었습니다.","JPN":"クリントンさんはもとは落ち着いた方でした。","ENG":"He used to be a very reserved man.","TWN":"克林頓先生本來是個很有禮貌的人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 역병에 걸려 죽음을 목도함에 어느 날부터 과장된 행동을 취하시기 시작했죠.","JPN":"ですが、疫病にかかり死を目撃してから、大げさな行動を取り始めました。","ENG":"But once he caught the plague and saw death coming, he started acting louder, more exaggerated.","TWN":"然而，自從目睹了因瘟疫而死的情景後，他開始表現出誇張的行為。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"슬픔을 감추려는 것도 있겠지만, 한편으로는 주변에 알리고 싶으신 겁니다.","JPN":"悲しみを隠そうということもあるのでしょうが、一方で周りの人々にわかってほしいのです。","ENG":"Part of it was to hide his grief. But he also wanted others to see.","TWN":"雖然有想要隱藏悲傷的心情，但另一方面也想讓周圍的人知道。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"천세를 누리지 못한 들, 자신의 삶이 결코 불행하지 않으리라고.","JPN":"千年万年を生きることができなくとも、自分の人生は決して不幸ではないと。","ENG":"That even if he wouldn't live a thousand years, his life still wasn't meaningless.","TWN":"即使無法穿越千世，也絕不會認為自己的生活是不幸的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제국의 병사들도 마찬가지입니다. 그들은 동료의 죽음이 명예로운 희생임을 알고 있죠.","JPN":"帝国の兵士たちも同じです。彼らは仲間の死は名誉ある犠牲だということをわかっています。","ENG":"The soldiers of the Empire are the same. They know their comrades died with honor.","TWN":"帝國的士兵也是如此。他們知道同伴的死亡是光榮的犧牲。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그렇기에 그들은 슬픔을 삼키고 웃음을 노래합니다.","JPN":"そのため彼らは悲しみを飲み、笑って歌うのです。","ENG":"So they swallow their sorrow and sing with laughter.","TWN":"因此，他們吞下悲傷，唱出歡笑。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"역병이 퍼진 세상의 끝에 동료들의 죽음이 희망의 초석이 될 것임을. 그 누구보다 간절히 바라면서요.","JPN":"疫病が広がった世界の果てに、仲間たちの死が希望の土台となることを、誰よりも切実に願いながら。","ENG":"They cling to the hope that their friends' deaths will lay the foundation for a better world.","TWN":"在瘟疫蔓延的世界盡頭，夥伴們的死亡將成為希望的基石。比任何人都更加迫切地期望著。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니 자책하실 필요 없습니다, 에스텔.","JPN":"ですのでご自分を責める必要はありません、エステル。","ENG":"So don't blame yourself, Esther.","TWN":"所以不必自責，艾斯特。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이곳에서 명을 다한 기사들은 살아남은 이들의 미래를 위한 방패가 되었으니.","JPN":"ここで命を落とした騎士たちは、生き残った者たちの未来を守る盾となったのですから。","ENG":"The knights who fell here became shields for the future of those who survived.","TWN":"在這裡，已盡使命的騎士們成為了倖存者未來的盾牌。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……부인께서는.","JPN":"……夫人は。","ENG":"...Ma'am.","TWN":"夫人……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"각오 없이 전장에 서는 이가 그들의 죽음 위에 설 자격이 있다고 생각하십니까?","JPN":"覚悟なしに戦場に立つ者が、彼らの死の上に立つ資格があると思われますか？","ENG":"Do you believe someone who walks into battle without resolve has the right to stand on their sacrifice?","TWN":"沒有覺悟就站在戰場上的人，你認為他們有資格站在死亡之上嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"글쎄요. 죽은 이는 말이 없으니 저는 잘 모르겠군요.","JPN":"どうでしょう。死者は何も話さないので、私にはわかりません。","ENG":"Who knows? The dead don't speak, so I couldn't say.","TWN":"嗯，死人是不會說話的，所以我不太清楚。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그에 대한 해답은 여생의 즐거움으로 남겨두면 그만 아니겠습니까?","JPN":"それについての答えは、残りの人生の楽しみに取っておいたらいかがです？","ENG":"Maybe that answer is something we can leave to the joys of life.","TWN":"關於這個答案，何不留待餘生的樂趣中去尋找呢？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"역시, 부인께서는 알렌 경을 닮으셨군요.","JPN":"やはり、夫人はアレン卿に似ています。","ENG":"You really are like Sir Allen.","TWN":"果然，夫人和艾倫卿很像。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 알렌이 저를 닮은 거랍니다?","JPN":"あら。アレンが私に似ているのですよ？","ENG":"Oh my. Allen takes after me, actually.","TWN":"喔，艾倫像我嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"처음 만난 순간부터 의문이었습니다.","JPN":"最初に出会ったときから疑問に思っていました。","ENG":"It puzzled me from the moment we met.","TWN":"從第一次見面開始就感到疑惑。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인께서 어떻게 별의 무구를, 그리고 알렌 경에 대해 알고 있는지.","JPN":"夫人はどうやって星の武具を、そしてアレン卿について知っているのか。","ENG":"How you knew about the Star Armaments and Sir Allen.","TWN":"夫人是如何知道星之武具，以及關於艾倫卿的事情的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 금방의 전투에서 백작령의 기사들이 별의 무구를 다루는 것을 보자 문득 떠오르더군요.","JPN":"ですが、先程の戦闘で伯爵領の騎士たちが星の武具を扱っているのを見て、ふと思い出したのです。","ENG":"But after seeing your knights use the Armaments in battle, something clicked.","TWN":"但是在剛才的戰鬥中，看到伯爵領地的騎士們使用星之武具時，我突然想到了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알렌 경이 이상하리만큼 별의 인도자에 관한 것들을 조사해왔고.","JPN":"アレン卿が怪しいくらい星の導き手について調査をしていて。","ENG":"Sir Allen was always oddly obsessed with researching the Star Guide.","TWN":"艾倫卿一直在調查有關星之引導者的事情，而且是異常地堅持。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그것에 관한 이야기를 할 때, 무척이나 괴로운 표정을 지으셨던 걸요.","JPN":"それについて話す時、とても辛そうな顔をしていたことを。","ENG":"And whenever he spoke of it, he looked utterly torn.","TWN":"提到那件事時，他的表情非常痛苦。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"THEMA_GREATSWORD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신이.","JPN":"あなたが。","ENG":"Are you–","TWN":"是你。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 버밍엄이, 별의 인도자인 겁니까?","JPN":"グレース・バーミンガムが、星の導き手なのですか？","ENG":"Is Grace Birmingham the Star Guide?","TWN":"葛瑞絲·伯明罕是星之引導者嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"날카로운 <color=#ffd34c>질문</color>인 것은 맞으나 제 말문이 막힐 정도는 아니로군요.","JPN":"確かに鋭い<color=#ffd34c>質問</color>ではありますが、言葉を失うほどではありませんでしたね。","ENG":"A sharp <color=#ffd34c>question</color>. But not sharp enough to leave me speechless.","TWN":"雖然這是個尖銳的<color=#ffd34c>問題</color>，但還不至於讓我無言以對。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"유감스러우나 그 질문에는 답해드릴 수 없을 것 같습니다.","JPN":"残念ですが、その質問にはお答えできそうにありません。","ENG":"I'm afraid I can't answer that one.","TWN":"很遺憾，我無法回答這個問題。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……괜찮습니다. 적어도 제 안에선 답을 내렸으니까요.","JPN":"……大丈夫です。少なくとも、私は選択をしましたから。","ENG":"...That's all right. I've already made my decision.","TWN":"……沒關係。至少我已經在心裡做出了決定。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"날이 늦었으니 먼저 들어가보겠습니다.","JPN":"もう遅いので、先に失礼します。","ENG":"It's getting late. I'll turn in for the night.","TWN":"天色已晚，我先回去了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……그레이스 경.","JPN":"……グレース卿。","ENG":"...Dame Grace.","TWN":"葛瑞絲……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"술잔에 비친 것이 전부인줄 알았으나, 별이 수놓은 밤하늘은 이리도 찬란하게 빛나는구나.","JPN":"杯に映っているものがすべてだと思ったのに、星空はあんなにも輝かしく光っているのね。","ENG":"I thought all I'd see in this glass was wine, but the stars in the sky still shine so brightly.","TWN":"以為酒杯中映出的就是全部，沒想到星星點綴的夜空竟如此燦爛輝煌。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_4"},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"간밤에 꿈을 꾸는 쪽은…… 어쩌면 나일지도 모르겠어.","JPN":"夢を見ているのは……もしかしたら私なのかもしれないわ。","ENG":"Maybe I'm the one dreaming tonight...","TWN":"昨晚做夢的那個人……說不定是我呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_5"}]`);export{e as default};